<?php
session_start();
require_once '../config/Database.php';
require_once '../classes/Auth.php';
require_once __DIR__ . '/includes/catalogo_cuentas_helpers.php';
$db=(new Database())->getConnection(); $db->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);
$auth=new Auth($db); $auth->requireLogin(); ensureAccountingCatalog($db); $message='';
if($_SERVER['REQUEST_METHOD']==='POST'){try{Auth::checkCSRF($_POST['csrf_token']??'');$action=(string)($_POST['action']??'');if($action==='save'){$id=(int)($_POST['id']??0);$code=trim((string)($_POST['codigo']??''));$name=trim((string)($_POST['nombre']??''));$type=in_array($_POST['tipo']??'',['Gasto','Balance'],true)?$_POST['tipo']:'Gasto';if($code===''||$name==='')throw new RuntimeException('El código y el nombre son obligatorios.');if(!preg_match('/^[0-9A-Za-z._-]{2,30}$/',$code))throw new RuntimeException('El código contiene caracteres no permitidos.');$v=[$code,$name,trim((string)($_POST['sinopsis']??'')),$type,!empty($_POST['permite_compras'])?1:0,!empty($_POST['activo'])?1:0];if($id>0){$v[]=$id;$db->prepare('UPDATE ah_catalogo_cuentas SET codigo=?,nombre=?,sinopsis=?,tipo=?,permite_compras=?,activo=? WHERE id=?')->execute($v);}else{$db->prepare("INSERT INTO ah_catalogo_cuentas(codigo,nombre,sinopsis,tipo,permite_compras,activo,orden,fuente) VALUES(?,?,?,?,?,?,9999,'CRUD financiero')")->execute($v);}$message='Cuenta guardada correctamente.';}elseif($action==='toggle'){$db->prepare('UPDATE ah_catalogo_cuentas SET activo=IF(activo=1,0,1) WHERE id=?')->execute([(int)($_POST['id']??0)]);$message='Estado de la cuenta actualizado.';}}catch(Throwable $e){$message=$e->getMessage();}}
$edit=null;if(!empty($_GET['edit'])){$st=$db->prepare('SELECT * FROM ah_catalogo_cuentas WHERE id=?');$st->execute([(int)$_GET['edit']]);$edit=$st->fetch(PDO::FETCH_ASSOC)?:null;}
$accounts=$db->query("SELECT * FROM ah_catalogo_cuentas ORDER BY FIELD(tipo,'Gasto','Balance'),orden,codigo,nombre")->fetchAll(PDO::FETCH_ASSOC);$csrf=Auth::generateCSRF();
function ccH($v):string{return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
?>
<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Catálogo contable | Acción Honduras</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap" rel="stylesheet"><link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css"><style>
