-columns:1fr}.main-wrapper{padding:18px}}
</style></head><body><?php include 'sidebar.php';?><main class="main-wrapper"><header class="header"><h1><i class="fa-solid fa-book-open" style="color:#34859B"></i> Catálogo de cuentas contables</h1><p>Fuente financiera independiente del POA · <?=count($accounts)?> registros</p></header><?php if($message):?><div class="notice"><?=ccH($message)?></div><?php endif;?><div class="layout">
<section class="card"><h2><?=$edit?'Editar cuenta':'Nueva cuenta'?></h2><form method="post"><input type="hidden" name="csrf_token" value="<?=ccH($csrf)?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=ccH($edit['id']??0)?>"><div class="field"><label>Código</label><input class="control" name="codigo" maxlength="30" required value="<?=ccH($edit['codigo']??'')?>"></div><div class="field"><label>Nombre</label><input class="control" name="nombre" maxlength="255" required value="<?=ccH($edit['nombre']??'')?>"></div><div class="field"><label>Tipo</label><select class="control" name="tipo"><option <?=($edit['tipo']??'Gasto')==='Gasto'?'selected':''?>>Gasto</option><option <?=($edit['tipo']??'')==='Balance'?'selected':''?>>Balance</option></select></div><div class="field"><label>Sinopsis / uso</label><textarea class="control" name="sinopsis" rows="7"><?=ccH($edit['sinopsis']??'')?></textarea></div><label class="check"><input type="checkbox" name="permite_compras" value="1" <?=!$edit||!empty($edit['permite_compras'])?'checked':''?>> Disponible en compras</label><label class="check"><input type="checkbox" name="activo" value="1" <?=!$edit||!empty($edit['activo'])?'checked':''?>> Cuenta activa</label><div class="actions"><button class="btn"><i class="fa-solid fa-floppy-disk"></i> Guardar</button><?php if($edit):?><a class="btn secondary" href="catalogo_cuentas.php">Cancelar</a><?php endif;?></div></form></section>
<section class="card"><h2>Cuentas registradas</h2><div class="toolbar"><input id="search" placeholder="Buscar código, nombre o sinopsis…" style="flex:1;min-width:220px"><select id="type"><option value="">Todos los tipos</option><option>Gasto</option><option>Balance</option></select><select id="state"><option value="">Todos los estados</option><option value="1">Activas</option><option value="0">Inactivas</option></select></div><div class="table-shell"><table data-table-ux="on" data-table-search="off"><thead><tr><th>Código</th><th>Cuenta</th><th>Tipo</th><th>Compras</th><th>Estado</th><th>Acciones</th></tr></thead><tbody id="accountRows"><?php foreach($accounts as $a):?><tr data-type="<?=ccH($a['tipo'])?>" data-state="<?=ccH($a['activo'])?>"><td><strong><?=ccH($a['codigo'])?></strong></td><td><strong><?=ccH($a['nombre'])?></strong><?php if($a['sinopsis']):?><br><small><?=ccH($a['sinopsis'])?></small><?php endif;?></td><td><span class="badge"><?=ccH($a['tipo'])?></span></td><td><span class="badge <?=!empty($a['permite_compras'])?'on':'off'?>"><?=!empty($a['permite_compras'])?'Sí':'No'?></span></td><td><span class="badge <?=!empty($a['activo'])?'on':'off'?>"><?=!empty($a['activo'])?'Activa':'Inactiva'?></span></td><td><div class="actions" style="margin:0"><a class="btn tiny" href="?edit=<?=$a['id']?>"><i class="fa-solid fa-pen"></i></a><form method="post"><input type="hidden" name="csrf_token" value="<?=ccH($csrf)?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?=$a['id']?>"><button class="btn tiny secondary" title="Activar/desactivar"><i class="fa-solid fa-power-off"></i></button></form></div></td></tr><?php endforeach;?></tbody></table></div></section></div></main><script>function filterRows(){const q=document.getElementById('search').value.toLocaleLowerCase('es'),t=document.getElementById('type').value,s=document.getElementById('state').value;document.querySelectorAll('#accountRows tr').forEach(r=>r.style.display=(!q||r.textContent.toLocaleLowerCase('es').includes(q))&&(!t||r.dataset.type===t)&&(!s||r.dataset.state===s)?'':'none')}document.querySelectorAll('#search,#type,#state').forEach(e=>e.addEventListener(e.tagName==='INPUT'?'input':'change',filterRows));</script></body></html>
